export const LEGAL_DOCS: LegalDoc[] = [{"key": "user-agreement", "title": "Пользовательское соглашение", "subtitle": "ООО «ОДИН НА ОДИН» Редакция от 06.06.2026", "blocks": [{"t": "h", "text": "1. ОБЩИЕ ПОЛОЖЕНИЯ"}, {"t": "p", "text": "1.1. Настоящее Пользовательское соглашение (далее — «Соглашение») регулирует отношения между ООО «ОДИН НА ОДИН» (далее — «Компания») и физическим лицом (далее — «Пользователь»), использующим AI-платформу OneOnOne (далее — «Сервис»)."}, {"t": "p", "text": "1.2. Реквизиты Компании:"}, {"t": "p", "text": "Полное наименование: Общество с ограниченной ответственностью «ОДИН НА ОДИН»"}, {"t": "p", "text": "ИНН: 9734021554"}, {"t": "p", "text": "ОГРН: 1257700576242"}, {"t": "p", "text": "КПП: 773401001"}, {"t": "p", "text": "Юридический адрес: 123592, г. Москва, ул. Маршала Катукова, д. 22, к. 1"}, {"t": "p", "text": "Электронная почта: support@oneononehq.com"}, {"t": "p", "text": "1.3. Использование Сервиса означает полное и безоговорочное принятие Пользователем условий настоящего Соглашения. Если Пользователь не согласен с условиями, он обязан прекратить использование Сервиса."}, {"t": "p", "text": "1.4. Компания вправе в одностороннем порядке изменять условия Соглашения. Новая редакция вступает в силу с момента её публикации на сайте. Продолжение использования Сервиса после публикации изменений означает принятие новой редакции."}, {"t": "h", "text": "2. ПРЕДМЕТ СОГЛАШЕНИЯ"}, {"t": "p", "text": "2.1. Компания предоставляет Пользователю доступ к Сервису OneOnOne — AI-платформе для проведения 1-on-1 встреч, управления командами, трекинга задач и аналитики на условиях, установленных настоящим Соглашением."}, {"t": "p", "text": "2.2. Сервис включает следующие функциональные возможности:"}, {"t": "ul", "items": ["планирование и проведение 1-on-1 встреч с AI-поддержкой;", "AI-ассистент «Пит» для управления командой;", "трекинг задач и их AI-декомпозиция;", "мониторинг настроения команды (Mood tracking);", "аналитика и отчётность;"]}, {"t": "p", "text": "учёт рабочего времени."}, {"t": "p", "text": "2.3. Доступ к расширенным функциям предоставляется в рамках платных тарифных планов согласно разделу 5 настоящего Соглашения."}, {"t": "h", "text": "3. РЕГИСТРАЦИЯ И УЧЁТНАЯ ЗАПИСЬ"}, {"t": "p", "text": "3.1. Для использования Сервиса Пользователь обязан пройти регистрацию, указав достоверные данные: имя, адрес электронной почты и номер телефона."}, {"t": "p", "text": "3.2. Пользователь несёт полную ответственность за сохранность своих учётных данных (логина и пароля) и за все действия, совершённые под его учётной записью."}, {"t": "p", "text": "3.3. При обнаружении несанкционированного доступа к учётной записи Пользователь обязан незамедлительно уведомить Компанию по адресу: support@oneononehq.com."}, {"t": "p", "text": "3.4. Компания вправе отказать в регистрации или заблокировать учётную запись без объяснения причин в случае нарушения условий настоящего Соглашения."}, {"t": "p", "text": "3.5. Пользователем может быть только физическое лицо, достигшее 18 лет, либо юридическое лицо в лице уполномоченного представителя."}, {"t": "h", "text": "4. ПРАВА И ОБЯЗАННОСТИ СТОРОН"}, {"t": "p", "text": "4.1. Пользователь обязуется:"}, {"t": "ul", "items": ["предоставлять достоверные данные при регистрации;", "не передавать доступ к учётной записи третьим лицам;", "не использовать Сервис в незаконных целях;", "не предпринимать попыток взлома, реверс-инжиниринга или несанкционированного доступа к инфраструктуре Сервиса;", "не распространять вредоносный контент через Сервис;"]}, {"t": "p", "text": "своевременно оплачивать выбранный тарифный план."}, {"t": "p", "text": "4.2. Пользователь вправе:"}, {"t": "ul", "items": ["использовать Сервис в соответствии с выбранным тарифным планом;", "обращаться в службу поддержки по адресу support@oneononehq.com;", "в любое время удалить свою учётную запись;"]}, {"t": "p", "text": "экспортировать свои данные в форматах, поддерживаемых Сервисом."}, {"t": "p", "text": "4.3. Компания обязуется:"}, {"t": "ul", "items": ["обеспечивать работоспособность Сервиса в соответствии с заявленными параметрами;", "хранить персональные данные Пользователей в соответствии с Политикой конфиденциальности и требованиями ФЗ-152;"]}, {"t": "p", "text": "уведомлять Пользователей об изменениях условий Соглашения."}, {"t": "p", "text": "4.4. Компания вправе:"}, {"t": "ul", "items": ["в любое время изменять, дополнять или прекращать работу Сервиса или его отдельных функций;", "проводить технические работы с временным ограничением доступа, уведомив Пользователей заблаговременно;"]}, {"t": "p", "text": "заблокировать учётную запись Пользователя при нарушении Соглашения."}, {"t": "h", "text": "5. ТАРИФЫ И ОПЛАТА"}, {"t": "p", "text": "5.1. Сервис предоставляется на следующих условиях:"}, {"t": "table", "head": ["Тариф", "Стоимость", "Участников", "Описание"], "rows": [["Free", "0 ₽/мес", "до 3", "1 команда, до 5 встреч/мес, история 14 дней, без AI"], ["Старт", "1 490 ₽/мес", "до 10", "1 команда, AI-ассистент Пит, встречи без лимита"], ["Команда", "490 ₽/чел/мес", "от 5 до 25", "до 5 команд, Пит, аналитика, Mood tracking"], ["Компания", "349 ₽/чел/мес", "от 25 до 100", "до 15 команд, видеозвонки, транскрипты, учёт времени"], ["Enterprise", "По согласованию", "без ограничений", "On-premise, SSO, SLA 99.9%, поддержка 24/7"]]}, {"t": "p", "text": "5.2. При оплате годовой подписки предоставляется скидка 20% от месячной стоимости. Годовая сумма списывается единовременно."}, {"t": "p", "text": "5.3. Оплата производится в российских рублях путём безналичного расчёта. Доступные способы оплаты указаны на странице оформления подписки."}, {"t": "p", "text": "5.4. Тарифный план активируется с момента поступления оплаты. Подписка на тарифы Старт и Компания возобновляется автоматически в начале каждого расчётного периода. По тарифам Команда и Компания стоимость рассчитывается исходя из фактического количества участников на момент выставления счёта."}, {"t": "p", "text": "5.5. Пользователь вправе отменить подписку в личном кабинете. При отмене доступ к платным функциям сохраняется до конца оплаченного периода. Возврат средств за неиспользованный период не производится, за исключением случаев, предусмотренных законодательством РФ."}, {"t": "p", "text": "5.6. Для тарифов Старт и Команда действует 14-дневный бесплатный пробный период без ввода платёжных данных."}, {"t": "p", "text": "5.7. Компания вправе изменять стоимость тарифов, уведомив Пользователей не менее чем за 30 дней до вступления изменений в силу."}, {"t": "h", "text": "6. ИНТЕЛЛЕКТУАЛЬНАЯ СОБСТВЕННОСТЬ"}, {"t": "p", "text": "6.1. Все права на Сервис, включая программное обеспечение, дизайн, контент, товарные знаки и иные объекты интеллектуальной собственности, принадлежат ООО «ОДИН НА ОДИН»."}, {"t": "p", "text": "6.2. Пользователю предоставляется неисключительная, непередаваемая лицензия на использование Сервиса исключительно в личных или корпоративных целях в рамках функционала, предусмотренного выбранным тарифом."}, {"t": "p", "text": "6.3. Запрещается копировать, воспроизводить, распространять или создавать производные продукты на основе Сервиса без письменного согласия Компании."}, {"t": "h", "text": "7. ОГРАНИЧЕНИЕ ОТВЕТСТВЕННОСТИ"}, {"t": "p", "text": "7.1. Сервис предоставляется «как есть». Компания не гарантирует бесперебойную и безошибочную работу Сервиса."}, {"t": "p", "text": "7.2. Компания не несёт ответственности за:"}, {"t": "ul", "items": ["прямые или косвенные убытки Пользователя, связанные с использованием или невозможностью использования Сервиса;", "действия третьих лиц;"]}, {"t": "p", "text": "временную недоступность Сервиса в связи с техническими работами или обстоятельствами непреодолимой силы."}, {"t": "p", "text": "7.3. Совокупная ответственность Компании перед Пользователем ни при каких обстоятельствах не превышает сумму, фактически уплаченную Пользователем за последний расчётный период."}, {"t": "h", "text": "8. РАСТОРЖЕНИЕ"}, {"t": "p", "text": "8.1. Пользователь вправе расторгнуть Соглашение, удалив учётную запись в личном кабинете или направив соответствующий запрос на support@oneononehq.com."}, {"t": "p", "text": "8.2. Компания вправе расторгнуть Соглашение в одностороннем порядке при нарушении Пользователем его условий, уведомив по электронной почте."}, {"t": "h", "text": "9. ПРИМЕНИМОЕ ПРАВО И СПОРЫ"}, {"t": "p", "text": "9.1. Настоящее Соглашение регулируется законодательством Российской Федерации."}, {"t": "p", "text": "9.2. Все споры решаются путём переговоров. При невозможности достижения согласия спор передаётся в суд по месту нахождения Компании — г. Москва."}]}, {"key": "offer", "title": "Публичная оферта", "subtitle": "ООО «ОДИН НА ОДИН» Редакция от 06.06.2026", "blocks": [{"t": "h", "text": "1. ОБЩИЕ ПОЛОЖЕНИЯ"}, {"t": "p", "text": "1.1. Настоящий документ является публичной офертой ООО «ОДИН НА ОДИН» (ИНН 9734021554, ОГРН 1257700576242, адрес: 123592, г. Москва, ул. Маршала Катукова, д. 22, к. 1; далее — «Исполнитель») в адрес любого физического или юридического лица (далее — «Заказчик») о заключении Договора на оказание услуг доступа к AI-платформе OneOnOne."}, {"t": "p", "text": "1.2. Настоящая Оферта является публичной в соответствии со ст. 437 Гражданского кодекса РФ."}, {"t": "p", "text": "1.3. Акцептом настоящей Оферты является факт оплаты Заказчиком одного из платных тарифных планов Сервиса. С момента поступления оплаты Договор считается заключённым."}, {"t": "h", "text": "2. ПРЕДМЕТ ДОГОВОРА"}, {"t": "p", "text": "2.1. Исполнитель обязуется предоставить Заказчику доступ к AI-платформе OneOnOne в объёме, соответствующем оплаченному тарифному плану, а Заказчик обязуется оплатить данные услуги в порядке и на условиях, установленных настоящей Офертой."}, {"t": "p", "text": "2.2. Услуги оказываются дистанционно через сеть Интернет по адресу сайта Сервиса."}, {"t": "h", "text": "3. СТОИМОСТЬ И ПОРЯДОК ОПЛАТЫ"}, {"t": "p", "text": "3.1. Стоимость услуг определяется выбранным тарифным планом:"}, {"t": "table", "head": ["Тариф", "Стоимость", "Участников", "Состав услуг"], "rows": [["Старт", "1 490 ₽/мес", "до 10", "1 команда, AI-ассистент Пит, встречи без лимита, история без ограничений"], ["Команда", "490 ₽/чел/мес", "от 5 до 25", "до 5 команд, Пит, AI-декомпозиция задач, Mood tracking, полная аналитика, экспорт CSV"], ["Компания", "349 ₽/чел/мес", "от 25 до 100", "до 15 команд, всё из Команда + видеозвонки, автотранскрипты, учёт рабочего времени, приоритетная поддержка"], ["Enterprise", "По согласованию", "без ограничений", "всё из Компания + On-premise, SSO/SAML, кастомные интеграции, SLA 99.9%, поддержка 24/7, выделенный менеджер"]]}, {"t": "p", "text": "3.2. При оплате годовой подписки предоставляется скидка 20%. Итоговая сумма списывается единовременно за 12 месяцев."}, {"t": "p", "text": "3.3. По тарифам Команда и Компания стоимость рассчитывается исходя из фактического количества участников на момент выставления счёта, но не менее минимального порога участников тарифа."}, {"t": "p", "text": "3.4. Оплата производится авансовым платежом за расчётный период путём безналичного перевода с использованием платёжных инструментов, доступных в Сервисе."}, {"t": "p", "text": "3.5. Обязательство Заказчика по оплате считается исполненным с момента поступления денежных средств на расчётный счёт Исполнителя."}, {"t": "p", "text": "3.6. Подписка возобновляется автоматически в начале каждого расчётного периода. Для отмены автопродления Заказчик должен самостоятельно отключить подписку в личном кабинете до даты следующего списания."}, {"t": "p", "text": "3.7. Для тарифов Старт и Команда действует 14-дневный бесплатный пробный период. В течение пробного периода оплата не взимается. По истечении пробного периода, если Заказчик не отменил подписку, производится автоматическое списание согласно выбранному тарифу."}, {"t": "h", "text": "4. ПРАВА И ОБЯЗАННОСТИ СТОРОН"}, {"t": "p", "text": "4.1. Исполнитель обязуется:"}, {"t": "ul", "items": ["обеспечить доступ к Сервису в объёме выбранного тарифа в течение 24 часов с момента поступления оплаты;", "поддерживать работоспособность Сервиса;", "обеспечить конфиденциальность данных Заказчика в соответствии с Политикой конфиденциальности;"]}, {"t": "p", "text": "уведомлять Заказчика об изменении тарифов не менее чем за 30 дней."}, {"t": "p", "text": "4.2. Заказчик обязуется:"}, {"t": "ul", "items": ["своевременно вносить оплату согласно выбранному тарифу;", "использовать Сервис в соответствии с Пользовательским соглашением;", "не допускать передачи доступа к учётной записи третьим лицам;"]}, {"t": "p", "text": "указывать достоверное количество участников при расчёте стоимости тарифов Команда и Компания."}, {"t": "h", "text": "5. ВОЗВРАТ ДЕНЕЖНЫХ СРЕДСТВ"}, {"t": "p", "text": "5.1. Возврат денежных средств производится в следующих случаях:"}, {"t": "ul", "items": ["технический сбой по вине Исполнителя, в результате которого Сервис был недоступен более 72 часов подряд в течение расчётного периода;", "двойное списание средств;"]}, {"t": "p", "text": "отмена подписки в течение 14 дней с момента первой оплаты при условии, что платные функции не использовались."}, {"t": "p", "text": "5.2. Для оформления возврата Заказчик направляет заявление на support@oneononehq.com с указанием реквизитов и описанием ситуации. Срок рассмотрения — 10 рабочих дней."}, {"t": "p", "text": "5.3. В остальных случаях возврат средств за неиспользованный период не производится."}, {"t": "h", "text": "6. ОТВЕТСТВЕННОСТЬ СТОРОН"}, {"t": "p", "text": "6.1. За неисполнение обязательств стороны несут ответственность в соответствии с законодательством РФ."}, {"t": "p", "text": "6.2. Совокупная ответственность Исполнителя ограничена суммой, фактически уплаченной Заказчиком за последний расчётный период."}, {"t": "p", "text": "6.3. Исполнитель не несёт ответственности за перебои в работе Сервиса, вызванные обстоятельствами непреодолимой силы, действиями третьих лиц или плановыми техническими работами."}, {"t": "h", "text": "7. СРОК ДЕЙСТВИЯ ОФЕРТЫ"}, {"t": "p", "text": "7.1. Оферта действует бессрочно до момента её отзыва Исполнителем."}, {"t": "p", "text": "7.2. Исполнитель вправе отозвать или изменить Оферту в любое время путём публикации новой редакции на сайте. Изменения не распространяются на уже оплаченные периоды."}, {"t": "h", "text": "8. ЗАКЛЮЧИТЕЛЬНЫЕ ПОЛОЖЕНИЯ"}, {"t": "p", "text": "8.1. К отношениям сторон применяется законодательство Российской Федерации."}, {"t": "p", "text": "8.2. Споры рассматриваются в суде по месту нахождения Исполнителя — г. Москва."}, {"t": "p", "text": "8.3. Реквизиты Исполнителя: ООО «ОДИН НА ОДИН», ИНН 9734021554, ОГРН 1257700576242, КПП 773401001, адрес: 123592, г. Москва, ул. Маршала Катукова, д. 22, к. 1, email: support@oneononehq.com"}]}, {"key": "pd-consent", "title": "Согласие на обработку персональных данных", "subtitle": "ООО «ОДИН НА ОДИН»", "blocks": [{"t": "p", "text": "Настоящим я, ___________________________________ (далее — «Субъект персональных данных»), свободно, своей волей и в своём интересе даю согласие Обществу с ограниченной ответственностью «ОДИН НА ОДИН» (ИНН 9734021554, ОГРН 1257700576242, адрес: 123592, г. Москва, ул. Маршала Катукова, д. 22, к. 1; далее — «Оператор») на обработку моих персональных данных на следующих условиях."}, {"t": "p", "text": "Перечень персональных данных: фамилия, имя, отчество; адрес электронной почты; номер телефона; данные платёжного инструмента; IP-адрес и технические данные устройства; данные об использовании Сервиса; записи встреч, задачи и иные данные, создаваемые в ходе работы с Сервисом."}, {"t": "p", "text": "Цели обработки: регистрация и идентификация; предоставление доступа к Сервису OneOnOne; обработка платежей; направление уведомлений; техническая поддержка; улучшение качества Сервиса; соблюдение законодательства РФ."}, {"t": "p", "text": "Перечень действий с персональными данными: сбор, запись, систематизация, накопление, хранение, уточнение, извлечение, использование, передача (предоставление), обезличивание, блокирование, удаление, уничтожение."}, {"t": "p", "text": "Способы обработки: автоматизированная и неавтоматизированная обработка."}, {"t": "p", "text": "Срок действия согласия: согласие действует с момента его предоставления до момента удаления учётной записи Субъекта персональных данных, либо до отзыва согласия."}, {"t": "p", "text": "Порядок отзыва согласия: Субъект персональных данных вправе в любое время отозвать настоящее Согласие, направив письменное заявление по адресу: 123592, г. Москва, ул. Маршала Катукова, д. 22, к. 1, или по электронной почте: support@oneononehq.com. Отзыв согласия влечёт прекращение предоставления доступа к Сервису."}, {"t": "p", "text": "Настоящее Согласие предоставляется путём совершения акцепта — нажатия кнопки «Зарегистрироваться», «Войти» или иной аналогичной кнопки при создании учётной записи в Сервисе."}]}, {"key": "privacy", "title": "Политика конфиденциальности", "subtitle": "ООО «ОДИН НА ОДИН» Редакция от 04.06.2026", "blocks": [{"t": "h", "text": "1. ОБЩИЕ ПОЛОЖЕНИЯ"}, {"t": "p", "text": "1.1. Настоящая Политика конфиденциальности (далее — «Политика») описывает порядок сбора, хранения, обработки и защиты персональных данных пользователей AI-платформы OneOnOne."}, {"t": "p", "text": "1.2. Оператор персональных данных:"}, {"t": "p", "text": "ООО «ОДИН НА ОДИН», ИНН 9734021554, ОГРН 1257700576242"}, {"t": "p", "text": "Адрес: 123592, г. Москва, ул. Маршала Катукова, д. 22, к. 1"}, {"t": "p", "text": "Email: support@oneononehq.com"}, {"t": "p", "text": "1.3. Политика разработана в соответствии с Федеральным законом от 27.07.2006 № 152-ФЗ «О персональных данных» и иными нормативными актами РФ."}, {"t": "p", "text": "1.4. Используя Сервис, Пользователь выражает согласие с условиями настоящей Политики."}, {"t": "h", "text": "2. СОСТАВ СОБИРАЕМЫХ ДАННЫХ"}, {"t": "p", "text": "2.1. Данные, предоставляемые Пользователем при регистрации и использовании Сервиса:"}, {"t": "ul", "items": ["фамилия, имя, отчество;", "адрес электронной почты;", "номер телефона;", "данные платёжного инструмента (обрабатываются платёжными системами, Компания хранит только результат транзакции);"]}, {"t": "p", "text": "фотография профиля (по желанию)."}, {"t": "p", "text": "2.2. Данные, собираемые автоматически:"}, {"t": "ul", "items": ["IP-адрес и данные об устройстве;", "тип и версия браузера/ОС;", "cookie-файлы и данные сессии;", "данные об использовании функций Сервиса (время входа, действия в системе);"]}, {"t": "p", "text": "журналы ошибок."}, {"t": "p", "text": "2.3. Данные, создаваемые в ходе работы с Сервисом:"}, {"t": "ul", "items": ["записи и транскрипты 1-on-1 встреч;", "задачи и их статусы;", "данные опросов настроения команды;"]}, {"t": "p", "text": "переписка с AI-ассистентом «Пит»."}, {"t": "h", "text": "3. ЦЕЛИ ОБРАБОТКИ ПЕРСОНАЛЬНЫХ ДАННЫХ"}, {"t": "p", "text": "Компания обрабатывает персональные данные в следующих целях:"}, {"t": "ul", "items": ["регистрация и идентификация Пользователя;", "предоставление доступа к функционалу Сервиса;", "обработка платежей и ведение расчётов;", "направление уведомлений, связанных с использованием Сервиса;", "техническая поддержка;", "улучшение качества Сервиса и разработка новых функций;", "соблюдение требований законодательства РФ;"]}, {"t": "p", "text": "обеспечение безопасности Сервиса."}, {"t": "h", "text": "4. ПРАВОВЫЕ ОСНОВАНИЯ ОБРАБОТКИ"}, {"t": "p", "text": "4.1. Обработка персональных данных осуществляется на основании:"}, {"t": "ul", "items": ["согласия субъекта персональных данных (ст. 6, ч. 1, п. 1 ФЗ-152);", "исполнения договора, стороной которого является субъект (ст. 6, ч. 1, п. 5 ФЗ-152);"]}, {"t": "p", "text": "соблюдения требований законодательства РФ (ст. 6, ч. 1, п. 2 ФЗ-152)."}, {"t": "h", "text": "5. ХРАНЕНИЕ И ЗАЩИТА ДАННЫХ"}, {"t": "p", "text": "5.1. Все персональные данные хранятся на серверах, расположенных на территории Российской Федерации, в соответствии с требованиями ст. 18.1 ФЗ-152."}, {"t": "p", "text": "5.2. Компания применяет следующие меры защиты:"}, {"t": "ul", "items": ["шифрование данных при передаче (TLS/HTTPS);", "шифрование данных при хранении;", "разграничение прав доступа сотрудников;", "регулярное резервное копирование;"]}, {"t": "p", "text": "мониторинг инцидентов безопасности."}, {"t": "p", "text": "5.3. Персональные данные хранятся в течение срока действия учётной записи Пользователя и в течение 3 лет после её удаления — в целях соблюдения требований законодательства. Платёжные данные хранятся в сроки, установленные законодательством о бухгалтерском учёте."}, {"t": "h", "text": "6. ПЕРЕДАЧА ДАННЫХ ТРЕТЬИМ ЛИЦАМ"}, {"t": "p", "text": "6.1. Компания не продаёт и не передаёт персональные данные Пользователей третьим лицам, за исключением следующих случаев:"}, {"t": "ul", "items": ["платёжным системам — для обработки транзакций;", "облачным провайдерам — для обеспечения работы инфраструктуры (в объёме, необходимом для оказания услуг);"]}, {"t": "p", "text": "по требованию уполномоченных государственных органов РФ в соответствии с законодательством."}, {"t": "p", "text": "6.2. При передаче данных третьим лицам Компания обеспечивает соблюдение ими требований ФЗ-152."}, {"t": "h", "text": "7. ПРАВА ПОЛЬЗОВАТЕЛЯ"}, {"t": "p", "text": "В соответствии с ФЗ-152 Пользователь имеет право:"}, {"t": "ul", "items": ["получить информацию об обработке своих персональных данных;", "потребовать уточнения, блокирования или уничтожения персональных данных;", "отозвать согласие на обработку персональных данных;"]}, {"t": "p", "text": "обжаловать действия Компании в Роскомнадзор (rkn.gov.ru)."}, {"t": "p", "text": "Для реализации прав направьте запрос на: support@oneononehq.com. Срок ответа — 30 дней."}, {"t": "h", "text": "8. COOKIE-ФАЙЛЫ"}, {"t": "p", "text": "8.1. Сервис использует cookie-файлы для обеспечения функциональности, хранения пользовательских настроек и аналитики."}, {"t": "p", "text": "8.2. Пользователь вправе отключить cookie в настройках браузера, однако это может привести к ограничению функциональности Сервиса."}, {"t": "h", "text": "9. ИЗМЕНЕНИЯ ПОЛИТИКИ"}, {"t": "p", "text": "Компания вправе обновлять настоящую Политику. Актуальная версия размещается на сайте. Продолжение использования Сервиса после публикации изменений означает согласие с новой редакцией."}]}, {"key": "cookie", "title": "Политика использования Cookie", "subtitle": "ООО «ОДИН НА ОДИН» Редакция от 04.06.2026", "blocks": [{"t": "h", "text": "1. ЧТО ТАКОЕ COOKIE"}, {"t": "p", "text": "Cookie — это небольшие текстовые файлы, которые сохраняются на вашем устройстве при посещении сайта OneOnOne. Они позволяют Сервису запоминать ваши предпочтения, поддерживать сессию авторизации и анализировать использование платформы."}, {"t": "h", "text": "2. КАКИЕ COOKIE МЫ ИСПОЛЬЗУЕМ"}, {"t": "table", "head": ["Тип", "Назначение", "Срок хранения"], "rows": [["Необходимые", "Авторизация, безопасность, базовая работа Сервиса", "Сессия / до 1 года"], ["Функциональные", "Запоминание настроек интерфейса, языка, предпочтений", "До 1 года"], ["Аналитические", "Анализ использования Сервиса, улучшение функционала", "До 2 лет"]]}, {"t": "h", "text": "3. УПРАВЛЕНИЕ COOKIE"}, {"t": "p", "text": "3.1. Вы можете в любой момент отключить или удалить cookie в настройках вашего браузера."}, {"t": "p", "text": "3.2. Отключение необходимых cookie может привести к невозможности авторизации и использования Сервиса."}, {"t": "p", "text": "3.3. Инструкции по управлению cookie для популярных браузеров доступны на официальных сайтах: Google Chrome, Mozilla Firefox, Safari, Microsoft Edge."}, {"t": "h", "text": "4. КОНТАКТЫ"}, {"t": "p", "text": "По вопросам, связанным с использованием cookie: support@oneononehq.com"}]}];
